const IS_PRODUCTION = (() => {
  try {
    return process.env.NODE_ENV === 'production';
  } catch (e) {
    console.error(e);
    return true;
  }
})();

export type LOG_MODE = 'production' | 'development';
export let LOG_MODE: LOG_MODE = IS_PRODUCTION ? 'production' : 'development';

export function setLogMode(mode: LOG_MODE) {
  return (LOG_MODE = mode);
}

/**
 * Logs a message or error in development mode only.
 * Does NOT throw - safe to use in catch blocks.
 *
 * @param messageOrError - String message or Error object to log
 * @param args - Additional arguments to log
 */
export function devLog(messageOrError: string | Error, ...args: any[]) {
  if (LOG_MODE === 'development') {
    if (typeof messageOrError !== 'string') {
      console.error(messageOrError, ...args);
    } else {
      console.trace(messageOrError, ...args);
    }
  }
}

/**
 * Throws an error in development mode only.
 * Use this when you want to assert a condition and fail loudly in dev.
 *
 * @param error - Error to throw in development mode
 */
export function devAssert(error: Error): void {
  if (LOG_MODE === 'development') {
    Error.captureStackTrace?.(error, devAssert);
    throw error;
  }
}

