import { milliseconds } from 'date-fns';

export const MSUnitMapper = {
  y: 'years',
  mo: 'months',
  mon: 'months',
  months: 'months',
  w: 'weeks',
  d: 'days',
  h: 'hours',
  m: 'minutes',
  min: 'minutes',
  s: 'seconds',
  ms: 'milliseconds',
} as const;

export const MSUnits = Object.keys(
  MSUnitMapper,
) as (keyof typeof MSUnitMapper)[];

export type MSTimeUnit = (typeof MSUnits)[number];

/**
 * A string representing time to be converted in milliseconds
 * @example:
 *  - '1s' // => 1000 (1 second)
 *  - '1y' // => 31556952000 (1 year)
 *  - see `ms.spec.ts`
 */
export type MSTimeString = number | `${number}${MSTimeUnit}`;

export const MS_REGEX = new RegExp(`^(\\d+)(${MSUnits.join('|')})$`);

/**
 * Converts MSTimeString to milliseconds
 * @example: ms(1s) // => 1000
 * @param timeString
 */
export function ms(timeString: MSTimeString): number {
  if (typeof timeString === 'number') {
    timeString = `${timeString}ms`;
  }

  const match = timeString.trim().match(MS_REGEX);

  if (!match) {
    throw new Error(`Invalid time string format: "${timeString}"`);
  }

  const [, numStr, unit] = match;
  const num = parseInt(numStr, 10);

  if (isNaN(num)) {
    throw new Error(`Invalid number from string '${timeString}'.`);
  }

  if (!hasOwnProperty(MSUnitMapper, unit)) {
    throw new Error(`Invalid time unit from string "${timeString}".`);
  }

  if (unit === 'ms') return num;

  const fullName = MSUnitMapper[unit];

  return milliseconds({ [fullName]: num });
}

function hasOwnProperty<Obj extends object>(
  object: Obj,
  key: any,
): key is keyof Obj {
  return Object.prototype.hasOwnProperty.call(object, key as never);
}

