     4→/**
     5→ * Core type definitions and public interfaces for the type validation system.
     6→ */
     7→
     8→export type AllTypes = {
     9→  string: {};
    10→  number: {};
    11→  null: {};
    12→  undefined: {};
    13→  boolean: {};
    14→  unknown: {};
    15→  any: {};
    16→  object: { properties: ObjectTypeProperties };
    17→  enum: { enum: ReadonlyArray<string> };
    18→  list: { items: TypeDefinition };
    19→  union: { union: ReadonlyArray<TypeDefinition> };
    20→  record: { record: TypeDefinition };
    21→  date: {};
    22→  function: {};
    23→  type: { '~typebox': TSchema };
    24→};
    25→
    26→export type ObjectTypeProperties = { [K: string]: TypeDefinition };
    27→
    28→export type TypeName = keyof AllTypes & {};
    29→
    30→/**
    31→ * Type definition using a compact string format.
    32→ * Format: `typeName[?][[]][?]`
    33→ */
    34→export type TypeDefinitionString =
    35→  `${TypeName}${'?' | ''}${'[]' | ''}${'?' | ''}`;
    36→
    37→/**
    38→ * Type definition using object-based format.
    39→ */
    40→export type ObjectBasedTypeDefinition =
    41→  | AllTypes['object']
    42→  | AllTypes['enum']
    43→  | AllTypes['list']
    44→  | AllTypes['union']
    45→  | AllTypes['record']
    46→  | AllTypes['type'];
    47→
    48→/**
    49→ * Union of all possible type definitions.
    50→ */
    51→export type TypeDefinition = TypeDefinitionString | ObjectBasedTypeDefinition;
    52→
    53→export type FunctionLike = (...params: ReadonlyArray<any>) => any;
    54→
    55→/**
    56→ * Compiled type with validation methods.
    57→ */
    58→export type Type<
    59→  _Definition extends TypeDefinition = TypeDefinition,
    60→  Result = unknown,
    61→> = {
    62→  '~typebox': TSchema;
    63→  list(): Type<any, Result[]>;
    64→  parse<T>(value: T, property?: string): Result;
    65→  parseList<T>(value: T, property?: string): Result[];
    66→  isValid(value: unknown): value is Result;
    67→};
    68→
    69→// Primitive type mapping
    70→type InferPrimitive<T extends string> = T extends 'string'
    71→  ? string
    72→  : T extends 'number'
    73→    ? number
    74→    : T extends 'boolean'
    75→      ? boolean
    76→      : T extends 'null'
    77→        ? null
    78→        : T extends 'undefined'
    79→          ? undefined
    80→          : T extends 'date'
    81→            ? Date
    82→            : T extends 'function'
    83→              ? FunctionLike
    84→              : T extends 'object'
    85→                ? object
    86→                : T extends 'unknown'
    87→                  ? unknown
    88→                  : T extends 'any'
    89→                    ? any
    90→                    : never;
    91→
