    96→    ? (InferPrimitive<Base> | undefined)[]
    97→    : T extends `${infer Base}[]`
    98→      ? InferPrimitive<Base>[]
    99→      : T extends `${infer Base}?`
   100→        ? InferPrimitive<Base> | undefined
   101→        : InferPrimitive<T>;
