export * from './any';
export * from './compute';
export * from './falsy';
export * from './general-types';
export * from './list';
export * from './object-types';
export * from './replace';
export * from './string-enum';
export * from './typeof';

/**
 * @file This file contains general-purpose utility types.
 */

import { Compute } from './compute';

/**
 * Represents an object with string keys and values of any type.
 */
export type AnyRecord = { [K: string]: any };

/**
 * Represents an object with string keys and values of an unknown type.
 * Safer than `AnyRecord`.
 */
export type UnknownRecord = { [K: string]: unknown };

/**
 * Extracts the resolved value type from a Promise.
 * @example PromiseValue<Promise<number>> // => number
 */
export type PromiseValue<T> = T extends Promise<infer R> ? R : T;

/**
 * Represents a value that could be a Promise or a direct value.
 */
export type MaybePromise<T> = Promise<T> | T;

/**
 * Flattens a complex intersection type into a single object for better readability.
 * @example
 * type R = Simplify<{ a: number } & { b: number }>;
 * // R is { a: number; b: number }
 */
export type Simplify<T> = [Exclude<T, BuiltIn>] extends [never]
  ? T
  : T extends ReadonlyArray<any>
    ? T
    : {
        [K in keyof T as Ternary<IsKnown<T[K]>, K>]: T[K];
      };

/**
 * Represents a function with any arguments and any return type.
 */
export type AnyFunction = ((...args: any) => any) | Function;

/**
 * Represents a value that can be a single item or an array of that item.
 */
export type MaybeArray<T> = T | T[];

export type IsAny<T> = 0 extends 1 & T ? true : false;

export type IsNever<T> = [T] extends [never] ? true : false;

export type IsUnion<T, U = T> = T extends U
  ? [U] extends [T]
    ? false
    : true
  : never;

export type IsNullable<T> =
  Extract<T, null | undefined> extends never ? false : true;

export type IsOptional<T> = Extract<T, undefined> extends never ? false : true;

export type IsUnknown<T> =
  IsNever<T> extends false
    ? T extends unknown
      ? unknown extends T
        ? IsAny<T> extends false
          ? true
          : false
        : false
      : false
    : false;

export type OnlyKnown<T> = IsKnown<T> extends true ? T : never;

export type IsKnown<T> =
  IsAny<T> extends true
    ? false
    : IsNever<T> extends true
      ? false
      : IsUnknown<T> extends true
        ? false
        : true;

/**
 * Returns Option if Value is not known.
 *
 * @example
 * ```ts
 * type num = CastUnknown<1, number>; // number
 * type str1 = CastUnknown<'123', number>; // '123'
 * type str2 = CastUnknown<'123', string>; // string
 * ```
 */
export type CastUnknown<Value, Option, Coerce extends Boolean = true> =
  IsKnown<Value> extends true
    ? IsUnknown<Value> extends false
      ? Coerce extends true
        ? [Exclude<Value, Option>] extends [never]
          ? Option
          : Value
        : Value
      : Option
    : Option;

export type Boolean = true | false;
/**
 * Shallow merge two types
 * @example
 * ```ts
 *  type test = Merge<{ a: 1; b: 3 }, { a: 2; c: 8 }> // { a:2, b:3, c:8 }
 * ```
 */
export type Merge<A, B, Level extends Depth = 'deep'> =
  //
  Level extends 'flat'
    ? A & B
    : A extends BuiltIn
      ? Merge<B, {}>
      : B extends BuiltIn
        ? A
        : {
            [K in keyof A as K extends keyof B ? never : K]: A[K];
          } & { [K in keyof B]: B[K] };

export type Primitive =
  | string
  | boolean
  | number
  | null
  | undefined
  | bigint
  | symbol;

export type Serializable =
  | Exclude<Primitive, bigint | symbol>
  | { [K: string]: Serializable }
  | ReadonlyArray<Serializable>;

export type SerializableOnly<T> = {
  [K in keyof T as T[K] extends Serializable ? K : never]: T[K] extends unknown
    ? T[K]
    : never;
};
